import React, { Fragment } from 'react'
import { Card, CardHeader, Container, Row } from 'reactstrap';
import Breadcrumb from '../components/common/Breadcrumb';
import NodeDashboard from '../components/common/NodeDashboard';
import { UserState } from '../context/User';

const Dashboard = () => {
  const { user } = UserState();
  const { nodes, setNodes } = UserState();
  const { context, setContext } = UserState();
  const fetchNode = async (para) => {
    let dataRaw = await fetch("/Data/Read", {
      method: "POST",
      headers: {
        "Content-type": "application/json;charset=utf-8",
        method: "POST",
      },
      body: JSON.stringify({
        accountId: para,
      })
    });
    let data = await dataRaw.json();
    console.log(data);
  };
  if (user) {
    fetchNode(user._id).then((result) => {
      console.log(result);
      if (result.Data._id === user._id) {
        let contentProject = result.Data.project.map(element => {
          return 
            (<Card>
                <CardHeader>
                  <h5>Products Category</h5>
                </CardHeader>
            </Card>
            );
        });
      }
    });
  }
  return (
    <Fragment>
      {
        user && <Breadcrumb title="Dashboard" parent="Dashboard" />
      }
      {
        user &&
        <Container fluid={true}>
          {result.Data.project.map((element)=>{

          })

          }
          <Card>
              <CardHeader>
								<h5>Products Category</h5>
							</CardHeader>
          </Card>
          <Row>
            <NodeDashboard title={`COD`} unit={`mg/l`} key={`1`} />
          </Row>
          {{contentProject}}
        </Container>
      }


    </Fragment>
  )
}

export default Dashboard;
